        #[arg(long, default_value = "true")]
        decompose: bool,

        /// Disable dynamic decomposition
        #[arg(long)]
        no_decompose: bool,

        /// Budget percentage threshold to trigger decomposition
        #[arg(long, default_value = "50")]
        decompose_threshold: u32,

